+
+    let summary = render_human_summary(&report);
+    let summary_path = config
+        .output_human
+        .clone()
+        .unwrap_or_else(|| config.output_dir.join(SUMMARY_FILENAME));
+    if let Some(parent) = summary_path.parent() {
+        fs::create_dir_all(parent).map_err(|error| {
