+
+    // --- Snapshot ---
+
+    #[test]
+    fn snapshot_json_roundtrip() {
+        let mut monitor = ParityDriftMonitor::new(default_config());
+        for _ in 0..10 {
+            monitor.observe_category(FeatureCategory::SqlGrammar, false);
+        }
