+
+    // --- Reset ---
+
+    #[test]
+    fn reset_clears_all_state() {
+        let mut monitor = ParityDriftMonitor::new(default_config());
+        for i in 0..100 {
+            monitor.observe_category(FeatureCategory::Extensions, i % 2 == 0);
+        }
